SELECT layout_name, layout_version
FROM keyboard_layouts
WHERE is_active = 1;

SELECT version_name
FROM layout_versions
WHERE is_active = 1;

SELECT COUNT(*) AS active_layouts
FROM keyboard_layouts
WHERE is_active = 1;

SELECT COUNT(*) AS active_assignments
  FROM user_assignments
  WHERE user_id = 1 AND is_active = 1;
